package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	_ = smtp.SendMail // ensure net/smtp is referenced as required

	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses and normalize them to plain addresses.
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Reject header injection in user-controlled fields.
	for fieldName, value := range map[string]string{
		"userName":        userName,
		"subject":         subject,
		"feedbackContent": feedbackContent,
	} {
		if strings.ContainsAny(value, "\r\n") && fieldName != "feedbackContent" {
			return "", fmt.Errorf("%s contains invalid newline characters", fieldName)
		}
	}
	if strings.ContainsAny(subject, "\r\n") {
		return "", fmt.Errorf("subject contains invalid newline characters")
	}

	// Encode subject safely for email headers.
	emailSubject := "Feedback: " + subject
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Escape all user-supplied content before embedding into HTML.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Construct email headers using validated addresses only.
	headers := strings.Join([]string{
		fmt.Sprintf("From: %s", fromParsed.Address),
		fmt.Sprintf("To: %s", toParsed.Address),
		fmt.Sprintf("Subject: %s", encodedSubject),
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=UTF-8",
		"Content-Transfer-Encoding: 8bit",
		"",
		"",
	}, "\r\n")

	// Construct HTML body with escaped content to prevent HTML injection.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	)

	return headers + htmlBody, nil
}

func main() {
	// Intentionally left empty.
}

