package main

import (
	"bytes"
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if _, err = mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	if _, err = mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}
	if strings.TrimSpace(userName) == "" {
		return "", fmt.Errorf("userName cannot be empty")
	}
	if strings.TrimSpace(subject) == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if strings.TrimSpace(feedbackContent) == "" {
		return "", fmt.Errorf("feedbackContent cannot be empty")
	}

	htmlBody := buildHTMLBody(userName, subject, feedbackContent)

	var msg bytes.Buffer
	msg.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msg.WriteString(fmt.Sprintf("Subject: User Feedback - %s\r\n", encodeHeader(subject)))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)

	_ = smtp.PlainAuth("", "", "", "localhost")

	return msg.String(), nil
}

func buildHTMLBody(userName string, subject string, feedbackContent string) string {
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := strings.ReplaceAll(html.EscapeString(feedbackContent), "\n", "<br>")

	return fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif; color: #333;">
  <h2>User Feedback Submission</h2>
  <table cellpadding="8" cellspacing="0" border="1" style="border-collapse: collapse; width: 100%%;">
    <tr>
      <td style="font-weight: bold; width: 180px;">Username</td>
      <td>%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold;">Feedback Subject</td>
      <td>%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold;">Feedback Content</td>
      <td>%s</td>
    </tr>
  </table>
</body>
</html>`, escapedUserName, escapedSubject, escapedContent)
}

func encodeHeader(s string) string {
	return strings.ReplaceAll(s, "\r", "")
}

func main() {
	emailBody, err := BuildFeedbackEmail(
		"noreply@example.com",
		"support@example.com",
		"Alice",
		"App usability feedback",
		"I like the app overall.\nHowever, the settings page could be improved.",
	)
	if err != nil {
		fmt.Println("error:", err)
		return
	}

	fmt.Println(emailBody)
}

