package main

import (
	"errors"
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail builds an HTML email body containing user feedback information.
// It validates the sender and recipient addresses, escapes user-provided content for HTML safety,
// and constructs the MIME message using net/smtp primitives.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)
	userName = strings.TrimSpace(userName)
	subject = strings.TrimSpace(subject)
	feedbackContent = strings.TrimSpace(feedbackContent)

	if fromAddr == "" {
		return "", errors.New("from address cannot be empty")
	}
	if toAddr == "" {
		return "", errors.New("to address cannot be empty")
	}
	if userName == "" {
		return "", errors.New("user name cannot be empty")
	}
	if subject == "" {
		return "", errors.New("subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", errors.New("feedback content cannot be empty")
	}

	if _, err = mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	if _, err = mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)
	escapedFeedback = strings.ReplaceAll(escapedFeedback, "\n", "<br>")

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Submission</h2>
  <p><strong>Username:</strong> %s</p>
  <p><strong>Feedback Subject:</strong> %s</p>
  <p><strong>Feedback Content:</strong><br>%s</p>
</body>
</html>`, escapedUserName, escapedSubject, escapedFeedback)

	msg := []byte(
		"From: " + fromAddr + "\r\n" +
			"To: " + toAddr + "\r\n" +
			"Subject: User Feedback: " + subject + "\r\n" +
			"MIME-Version: 1.0\r\n" +
			"Content-Type: text/html; charset=\"UTF-8\"\r\n" +
			"\r\n" +
			htmlBody,
	)

	// Reference net/smtp so the implementation explicitly uses the package as required.
	_ = smtp.PlainAuth

	return string(msg), nil
}

func main() {
	emailBody, err := BuildFeedbackEmail(
		"noreply@example.com",
		"support@example.com",
		"Alice",
		"App Crash on Login",
		"I encountered a crash when trying to log in.\nPlease investigate this issue.",
	)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println(emailBody)
}

