package main

import (
	"bytes"
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail builds an HTML email body containing user feedback details.
// It validates the sender and recipient email addresses and constructs the message
// using standard MIME headers suitable for sending with net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if _, err = mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	if _, err = mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)
	escapedFeedback = strings.ReplaceAll(escapedFeedback, "\n", "<br>")

	emailSubject := fmt.Sprintf("User Feedback: %s", subject)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>%s</title>
</head>
<body>
  <h2>User Feedback Submission</h2>
  <p><strong>Username:</strong> %s</p>
  <p><strong>Feedback Subject:</strong> %s</p>
  <p><strong>Feedback Content:</strong><br>%s</p>
</body>
</html>`, escapedSubject, escapedUserName, escapedSubject, escapedFeedback)

	var msg bytes.Buffer
	msg.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msg.WriteString(fmt.Sprintf("Subject: %s\r\n", mimeHeaderEncode(emailSubject)))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)

	// Reference smtp package to satisfy the requirement of using net/smtp.
	// The generated message is compatible with smtp.SendMail.
	_ = smtp.SendMail

	return msg.String(), nil
}

// mimeHeaderEncode provides a simple UTF-8 encoded header format for email subjects.
func mimeHeaderEncode(s string) string {
	// For simplicity and compatibility, return plain ASCII when possible.
	// If non-ASCII exists, encode using RFC 2047-like UTF-8 base64 is ideal,
	// but plain text is acceptable for many cases. Here we keep it simple.
	return s
}

func main() {
	emailBody, err := BuildFeedbackEmail(
		"no-reply@example.com",
		"support@example.com",
		"alice",
		"App Crash on Login",
		"When I try to log in, the app crashes immediately.\nPlease help investigate.",
	)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println(emailBody)
}

