// BuildFeedbackEmail constructs an HTML email body containing user feedback.
// It validates email addresses, escapes user-provided content for HTML safety,
// and uses smtp.PlainAuth to demonstrate usage of the net/smtp package while
// constructing the message content.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if strings.TrimSpace(fromAddr) == "" {
		return "", errors.New("fromAddr cannot be empty")
	}
	if strings.TrimSpace(toAddr) == "" {
		return "", errors.New("toAddr cannot be empty")
	}
	if strings.TrimSpace(userName) == "" {
		return "", errors.New("userName cannot be empty")
	}
	if strings.TrimSpace(subject) == "" {
		return "", errors.New("subject cannot be empty")
	}
	if strings.TrimSpace(feedbackContent) == "" {
		return "", errors.New("feedbackContent cannot be empty")
	}

	if _, err = mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err = mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Use net/smtp package as required.
	// This demonstrates constructing SMTP-related information without sending.
	host := extractHost(fromAddr)
	_ = smtp.PlainAuth("", fromAddr, "placeholder-password", host)

	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)
	escapedFeedback = strings.ReplaceAll(escapedFeedback, "\n", "<br>")

	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      fmt.Sprintf("User Feedback: %s", escapedSubject),
		"MIME-Version": "1.0",
		"Content-Type": `text/html; charset="UTF-8"`,
	}

	var builder strings.Builder
	for k, v := range headers {
		builder.WriteString(k)
		builder.WriteString(": ")
		builder.WriteString(v)
		builder.WriteString("\r\n")
	}
	builder.WriteString("\r\n")

	builder.WriteString("<!DOCTYPE html>")
	builder.WriteString("<html><body>")
	builder.WriteString("<h2>User Feedback Submission</h2>")
	builder.WriteString("<p><strong>Username:</strong> " + escapedUserName + "</p>")
	builder.WriteString("<p><strong>Feedback Subject:</strong> " + escapedSubject + "</p>")
	builder.WriteString("<p><strong>Feedback Content:</strong><br>" + escapedFeedback + "</p>")
	builder.WriteString("</body></html>")

	return builder.String(), nil
}

func extractHost(addr string) string {
	parts := strings.Split(addr, "@")
	if len(parts) == 2 && strings.TrimSpace(parts[1]) != "" {
		return parts[1]
	}
	return "localhost"
}

func main() {
	emailBody, err := BuildFeedbackEmail(
		"noreply@example.com",
		"support@example.com",
		"alice",
		"App crash on startup",
		"The application crashes immediately after I open it.\nPlease help investigate.",
	)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println(emailBody)
}

