package main

import (
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs an RFC 5322-style email message with an HTML body
// containing the submitted user feedback. The returned string includes headers and
// body and is ready to be passed to smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	if strings.ContainsAny(fromAddr, "\r\n") || strings.ContainsAny(toAddr, "\r\n") ||
		strings.ContainsAny(userName, "\r\n") || strings.ContainsAny(subject, "\r\n") {
		return "", fmt.Errorf("input contains invalid newline characters")
	}

	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	headers := make(map[string]string)
	headers["From"] = fromAddr
	headers["To"] = toAddr
	headers["Subject"] = emailSubject
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = `text/html; charset="UTF-8"`

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div>
    <strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, safeUserName, safeSubject, safeFeedbackContent)

	var builder strings.Builder
	for _, key := range []string{"From", "To", "Subject", "MIME-Version", "Content-Type"} {
		builder.WriteString(fmt.Sprintf("%s: %s\r\n", key, headers[key]))
	}
	builder.WriteString("\r\n")
	builder.WriteString(htmlBody)

	emailMessage := builder.String()

