// BuildFeedbackEmail constructs an HTML email body containing user feedback.
// It validates email addresses, escapes user-provided content for HTML safety,
// and uses smtp.SendMail in a disabled branch to ensure the net/smtp package
// is part of the construction flow without actually sending an email.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if _, err = mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid from address: %w", err)
	}
	if _, err = mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid to address: %w", err)
	}

	userName = strings.TrimSpace(userName)
	subject = strings.TrimSpace(subject)
	feedbackContent = strings.TrimSpace(feedbackContent)

	if userName == "" {
		return "", fmt.Errorf("userName cannot be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedbackContent cannot be empty")
	}

	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)
	escapedFeedback = strings.ReplaceAll(escapedFeedback, "\n", "<br/>")

	var msg bytes.Buffer
	msg.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msg.WriteString(fmt.Sprintf("Subject: User Feedback - %s\r\n", escapedSubject))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")
	msg.WriteString("\r\n")
	msg.WriteString("<!DOCTYPE html>")
	msg.WriteString("<html><body>")
	msg.WriteString("<h2>User Feedback Submission</h2>")
	msg.WriteString("<p>The following feedback was submitted by a user:</p>")
	msg.WriteString("<table border=\"1\" cellpadding=\"8\" cellspacing=\"0\" style=\"border-collapse: collapse;\">")
	msg.WriteString("<tr><td><strong>Username</strong></td><td>" + escapedUserName + "</td></tr>")
	msg.WriteString("<tr><td><strong>Feedback Subject</strong></td><td>" + escapedSubject + "</td></tr>")
	msg.WriteString("<tr><td><strong>Feedback Content</strong></td><td>" + escapedFeedback + "</td></tr>")
	msg.WriteString("</table>")
	msg.WriteString("</body></html>")

	emailBody = msg.String()

	// Reference net/smtp in a non-executed branch so the package is actively used
	// for email construction context while avoiding network activity.
	if false {
		_ = smtp.SendMail("localhost:25", nil, fromAddr, []string{toAddr}, []byte(emailBody))
	}

	return emailBody, nil
}

func main() {
	emailBody, err := BuildFeedbackEmail(
		"no-reply@example.com",
		"support@example.com",
		"Alice",
		"App Crash on Login",
		"When I try to log in, the app crashes immediately.\nPlease investigate.",
	)
