	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)
	escapedContent = strings.ReplaceAll(escapedContent, "\n", "<br>")
	escapedContent = strings.ReplaceAll(escapedContent, "\r", "")

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Submission</h2>
  <p><strong>User Name:</strong> %s</p>
  <p><strong>Feedback Subject:</strong> %s</p>
  <p><strong>Feedback Content:</strong><br>%s</p>
